  contains?: JsonSchema;
  propertyNames?: JsonSchema;
  examples?: unknown[];
  if?: JsonSchema | boolean;
  then?: JsonSchema | boolean;
  else?: JsonSchema | boolean;
  contentEncoding?: string;
  contentMediaType?: string;
